import{_ as t,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"平台功能: 計畫與程式碼審查 | Plannotator","description":"學習 Plannotator 的平台功能，包括計畫審查和程式碼審查。掌握視覺化審查、新增註解、圖像標註等核心技能。","frontmatter":{"title":"平台功能: 計畫與程式碼審查 | Plannotator","sidebarTitle":"審查 AI 計畫和程式碼","subtitle":"平台功能: 計畫與程式碼審查","description":"學習 Plannotator 的平台功能，包括計畫審查和程式碼審查。掌握視覺化審查、新增註解、圖像標註等核心技能。","order":2},"headers":[],"relativePath":"zh-tw/backnotprop/plannotator/platforms/index.md","filePath":"zh-tw/backnotprop/plannotator/platforms/index.md"}'),i={name:"zh-tw/backnotprop/plannotator/platforms/index.md"};function n(l,a,d,s,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章節介紹 Plannotator 的兩大核心功能：<strong>計畫審查</strong>和<strong>程式碼審查</strong>。你將學會如何視覺化審查 AI 產生的計畫、新增各類註解、附加圖像標註，以及審查 git diff 程式碼變更。</p><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">開始前請確認</p><p>在學習本章節之前，請確保你已完成以下準備：</p><ul><li>✅ 已完成 <a href="./../start/getting-started/">快速開始</a> 教學</li><li>✅ 已安裝 Plannotator 外掛（<a href="./../start/installation-claude-code/">Claude Code</a> 或 <a href="./../start/installation-opencode/">OpenCode</a>）</li></ul></div><h2 id="本章內容" tabindex="-1">本章內容 <a class="header-anchor" href="#本章內容" aria-label="Permalink to &quot;本章內容&quot;">​</a></h2><h3 id="計畫審查" tabindex="-1">計畫審查 <a class="header-anchor" href="#計畫審查" aria-label="Permalink to &quot;計畫審查&quot;">​</a></h3><p>學習如何審查 AI 產生的執行計畫，新增修改建議，讓 AI 按你的意圖執行。</p><table tabindex="0"><thead><tr><th>教學</th><th>說明</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">計畫審查基礎</a></td><td>學會使用 Plannotator 視覺化審查 AI 產生的計畫，包括批准或拒絕計畫</td></tr><tr><td><a href="./plan-review-annotations/">新增計畫註解</a></td><td>掌握如何在計畫中新增不同類型的註解（刪除、取代、插入、評論）</td></tr><tr><td><a href="./plan-review-images/">新增圖像標註</a></td><td>學會在計畫審查中附加圖像，並使用畫筆、箭頭、圓形工具進行標註</td></tr></tbody></table><h3 id="程式碼審查" tabindex="-1">程式碼審查 <a class="header-anchor" href="#程式碼審查" aria-label="Permalink to &quot;程式碼審查&quot;">​</a></h3><p>學習如何審查程式碼變更，新增行級註解，在提交前發現問題。</p><table tabindex="0"><thead><tr><th>教學</th><th>說明</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td><a href="./code-review-annotations/">新增程式碼註解</a></td><td>掌握如何在程式碼審查中新增行級註解（comment/suggestion/concern）</td></tr><tr><td><a href="./code-review-diff-types/">切換 Diff 檢視</a></td><td>學會在程式碼審查中切換不同的 diff 類型（uncommitted/staged/last commit/branch）</td></tr></tbody></table><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推薦學習順序</p><p>根據你的使用情境，選擇合適的學習路徑：</p><p><strong>路徑 A：計畫審查優先</strong>（推薦新手）</p><ol><li><a href="./plan-review-basics/">計畫審查基礎</a> → 先學會基本的計畫審查流程</li><li><a href="./plan-review-annotations/">新增計畫註解</a> → 學習如何精確修改計畫</li><li><a href="./plan-review-images/">新增圖像標註</a> → 用圖像更清晰地表達意圖</li><li>然後再學習程式碼審查系列</li></ol><p><strong>路徑 B：程式碼審查優先</strong>（適合有 Code Review 經驗的開發者）</p><ol><li><a href="./code-review-basics/">程式碼審查基礎</a> → 熟悉程式碼審查介面</li><li><a href="./code-review-annotations/">新增程式碼註解</a> → 學習行級註解</li><li><a href="./code-review-diff-types/">切換 Diff 檢視</a> → 掌握不同 diff 類型</li><li>然後再學習計畫審查系列</li></ol></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，你可以繼續學習：</p><ul><li><a href="./../advanced/url-sharing/">URL 分享</a> - 透過 URL 分享計畫和註解，實現團隊協作</li><li><a href="./../advanced/obsidian-integration/">Obsidian 整合</a> - 將批准的計畫自動儲存到 Obsidian</li><li><a href="./../advanced/remote-mode/">遠端模式</a> - 在 SSH、devcontainer、WSL 環境中使用 Plannotator</li></ul>',16)])])}const b=t(i,[["render",n]]);export{f as __pageData,b as default};
